class Twitter:
    def __init__(self):
        self.count = 0
        self.tweetMap = defaultdict(list)
        self.followMap = defaultdict(set)

    def postTweet(self, userId: int, tweetId: int) -> None:
        self.tweetMap[userId].append((self.count, tweetId))
        self.count -= 1

    def getNewsFeed(self, userId: int) -> List[int]:
        res = []
        heap = []
        self.followMap[userId].add(userId)
        for fId in self.followMap[userId]:
            if fId in self.tweetMap:
                idx = len(self.tweetMap[fId]) - 1
                count, tweetId = self.tweetMap[fId][idx]
                heap.append((count, tweetId, fId, idx - 1))
        heapq.heapify(heap)
        while heap and len(res) < 10:
            count, tweetId, fId, idx = heapq.heappop(heap)
            res.append(tweetId)
            if idx >= 0:
                count, tweetId = self.tweetMap[fId][idx]
                heapq.heappush(heap, (count, tweetId, fId, idx - 1))
        return res

    def follow(self, followerId: int, followeeId: int) -> None:
        self.followMap[followerId].add(followeeId)

    def unfollow(self, followerId: int, followeeId: int) -> None:
        self.followMap[followerId].discard(followeeId)

solution_js:
var Twitter = function() {
    this.count = 0;
    this.tweetMap = new Map();
    this.followMap = new Map();
};

Twitter.prototype.postTweet = function(userId, tweetId) {
    if (!this.tweetMap.has(userId)) this.tweetMap.set(userId, []);
    this.tweetMap.get(userId).push([this.count++, tweetId]);
};

Twitter.prototype.getNewsFeed = function(userId) {
    const res = [];
    const heap = new MaxPriorityQueue({ priority: x => x[0] });
    const follows = this.followMap.get(userId) || new Set();
    follows.add(userId);
    for (const fId of follows) {
        const tweets = this.tweetMap.get(fId);
        if (tweets && tweets.length) {
            const idx = tweets.length - 1;
            heap.enqueue([tweets[idx][0], tweets[idx][1], fId, idx - 1]);
        }
    }
    while (heap.size() && res.length < 10) {
        const [, tweetId, fId, idx] = heap.dequeue().element;
        res.push(tweetId);
        if (idx >= 0) {
            const tweets = this.tweetMap.get(fId);
            heap.enqueue([tweets[idx][0], tweets[idx][1], fId, idx - 1]);
        }
    }
    return res;
};

Twitter.prototype.follow = function(followerId, followeeId) {
    if (!this.followMap.has(followerId)) this.followMap.set(followerId, new Set());
    this.followMap.get(followerId).add(followeeId);
};

Twitter.prototype.unfollow = function(followerId, followeeId) {
    const s = this.followMap.get(followerId);
    if (s) s.delete(followeeId);
};

