class MedianFinder:
    def __init__(self):
        self.small = []  # max-heap (negated)
        self.large = []  # min-heap

    def addNum(self, num: int) -> None:
        if self.large and num > self.large[0]:
            heapq.heappush(self.large, num)
        else:
            heapq.heappush(self.small, -num)
        if len(self.small) > len(self.large) + 1:
            heapq.heappush(self.large, -heapq.heappop(self.small))
        if len(self.large) > len(self.small) + 1:
            heapq.heappush(self.small, -heapq.heappop(self.large))

    def findMedian(self) -> float:
        if len(self.small) > len(self.large):
            return -self.small[0]
        if len(self.large) > len(self.small):
            return self.large[0]
        return (-self.small[0] + self.large[0]) / 2.0

solution_js:
var MedianFinder = function() {
    this.small = new MaxPriorityQueue();
    this.large = new MinPriorityQueue();
};

MedianFinder.prototype.addNum = function(num) {
    if (this.large.size() && num > this.large.front().element) {
        this.large.enqueue(num);
    } else {
        this.small.enqueue(num);
    }
    if (this.small.size() > this.large.size() + 1) {
        this.large.enqueue(this.small.dequeue().element);
    }
    if (this.large.size() > this.small.size() + 1) {
        this.small.enqueue(this.large.dequeue().element);
    }
};

MedianFinder.prototype.findMedian = function() {
    if (this.small.size() > this.large.size()) return this.small.front().element;
    if (this.large.size() > this.small.size()) return this.large.front().element;
    return (this.small.front().element + this.large.front().element) / 2;
};

var subsets = function(nums) {
    const res = [];
    const subset = [];
    function backtrack(i) {
        if (i >= nums.length) {
            res.push([...subset]);
            return;
        }
        subset.push(nums[i]);
        backtrack(i + 1);
        subset.pop();
        backtrack(i + 1);
    }
    backtrack(0);
    return res;
};

var combinationSum = function(candidates, target) {
    const res = [];
    function backtrack(i, cur, total) {
        if (total === target) { res.push([...cur]); return; }
        if (i >= candidates.length || total > target) return;
        cur.push(candidates[i]);
        backtrack(i, cur, total + candidates[i]);
        cur.pop();
        backtrack(i + 1, cur, total);
    }
    backtrack(0, [], 0);
    return res;
};

