def permute(self, nums: List[int]) -> List[List[int]]:
    res = []
    def backtrack(perm):
        if len(perm) == len(nums):
            res.append(perm[:])
            return
        for n in nums:
            if n not in perm:
                perm.append(n)
                backtrack(perm)
                perm.pop()
    backtrack([])
    return res

solution_js:
var permute = function(nums) {
    const res = [];
    function backtrack(perm) {
        if (perm.length === nums.length) {
            res.push([...perm]);
            return;
        }
        for (const n of nums) {
            if (!perm.includes(n)) {
                perm.push(n);
                backtrack(perm);
                perm.pop();
            }
        }
    }
    backtrack([]);
    return res;
};

var subsetsWithDup = function(nums) {
    nums.sort((a, b) => a - b);
    const res = [];
    function backtrack(i, subset) {
        if (i >= nums.length) {
            res.push([...subset]);
            return;
        }
        subset.push(nums[i]);
        backtrack(i + 1, subset);
        subset.pop();
        while (i + 1 < nums.length && nums[i] === nums[i + 1]) i++;
        backtrack(i + 1, subset);
    }
    backtrack(0, []);
    return res;
};

