        for (let j = i; j < candidates.length; j++) {
            if (total + candidates[j] > target) break;
            if (j > i && candidates[j] === candidates[j - 1]) continue;
            cur.push(candidates[j]);
            backtrack(j + 1, cur, total + candidates[j]);
            cur.pop();
        }
    }
    backtrack(0, [], 0);
    return res;
};

