def partition(self, s: str) -> List[List[str]]:
    res = []
    part = []
    def backtrack(i):
        if i >= len(s):
            res.append(part[:])
            return
        for j in range(i, len(s)):
            if s[i:j+1] == s[i:j+1][::-1]:
                part.append(s[i:j+1])
                backtrack(j + 1)
                part.pop()
    backtrack(0)
    return res

solution_js:
var partition = function(s) {
    const res = [];
    function isPalin(str, l, r) {
        while (l < r) { if (str[l++] !== str[r--]) return false; }
        return true;
    }
    function backtrack(i, part) {
        if (i >= s.length) { res.push([...part]); return; }
        for (let j = i; j < s.length; j++) {
            if (isPalin(s, i, j)) {
                part.push(s.substring(i, j + 1));
                backtrack(j + 1, part);
                part.pop();
            }
        }
    }
    backtrack(0, []);
    return res;
};

