def letterCombinations(self, digits: str) -> List[str]:
    if not digits:
        return []
    phone = {'2':'abc','3':'def','4':'ghi','5':'jkl',
             '6':'mno','7':'pqrs','8':'tuv','9':'wxyz'}
    res = []
    def backtrack(i, cur):
        if i == len(digits):
            res.append(cur)
            return
        for c in phone[digits[i]]:
            backtrack(i + 1, cur + c)
    backtrack(0, '')
    return res

solution_js:
var letterCombinations = function(digits) {
    if (!digits.length) return [];
    const phone = {'2':'abc','3':'def','4':'ghi','5':'jkl',
                   '6':'mno','7':'pqrs','8':'tuv','9':'wxyz'};
    const res = [];
    function backtrack(i, cur) {
        if (i === digits.length) { res.push(cur); return; }
        for (const c of phone[digits[i]]) {
            backtrack(i + 1, cur + c);
        }
    }
    backtrack(0, '');
    return res;
};

var solveNQueens = function(n) {
    const res = [];
    const cols = new Set(), posDiag = new Set(), negDiag = new Set();
    const board = Array.from({length: n}, () => Array(n).fill('.'));
    function backtrack(r) {
        if (r === n) {
            res.push(board.map(row => row.join('')));
            return;
        }
        for (let c = 0; c < n; c++) {
            if (cols.has(c) || posDiag.has(r+c) || negDiag.has(r-c)) continue;
            cols.add(c); posDiag.add(r+c); negDiag.add(r-c);
            board[r][c] = 'Q';
            backtrack(r + 1);
            cols.delete(c); posDiag.delete(r+c); negDiag.delete(r-c);
            board[r][c] = '.';
        }
    }
    backtrack(0);
    return res;
};

