    if (!node) return null;
    const oldToNew = new Map();
    function dfs(node) {
        if (oldToNew.has(node)) return oldToNew.get(node);
        const copy = new _Node(node.val);
        oldToNew.set(node, copy);
        for (const nei of node.neighbors) {
            copy.neighbors.push(dfs(nei));
        }
        return copy;
    }
    return dfs(node);
};

