def maxAreaOfIsland(self, grid: List[List[int]]) -> int:
    rows, cols = len(grid), len(grid[0])
    def dfs(r, c):
        if r < 0 or c < 0 or r >= rows or c >= cols or grid[r][c] == 0:
            return 0
        grid[r][c] = 0
        return 1 + dfs(r+1,c) + dfs(r-1,c) + dfs(r,c+1) + dfs(r,c-1)
    maxArea = 0
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 1:
                maxArea = max(maxArea, dfs(r, c))
    return maxArea

