var maxAreaOfIsland = function(grid) {
    const rows = grid.length, cols = grid[0].length;
    function dfs(r, c) {
        if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] === 0) return 0;
        grid[r][c] = 0;
        return 1 + dfs(r+1,c) + dfs(r-1,c) + dfs(r,c+1) + dfs(r,c-1);
    }
    let max = 0;
    for (let r = 0; r < rows; r++)
        for (let c = 0; c < cols; c++)
            if (grid[r][c] === 1) max = Math.max(max, dfs(r,c));
    return max;
};

var pacificAtlantic = function(heights) {
    const rows = heights.length, cols = heights[0].length;
    const pac = new Set(), atl = new Set();
    function dfs(r, c, visit, prev) {
        const key = r + ',' + c;
        if (r < 0 || c < 0 || r >= rows || c >= cols ||
            visit.has(key) || heights[r][c] < prev) return;
        visit.add(key);
        dfs(r+1,c,visit,heights[r][c]); dfs(r-1,c,visit,heights[r][c]);
        dfs(r,c+1,visit,heights[r][c]); dfs(r,c-1,visit,heights[r][c]);
    }
    for (let c = 0; c < cols; c++) {
        dfs(0,c,pac,heights[0][c]);
        dfs(rows-1,c,atl,heights[rows-1][c]);
    }
    for (let r = 0; r < rows; r++) {
        dfs(r,0,pac,heights[r][0]);
        dfs(r,cols-1,atl,heights[r][cols-1]);
    }
    const res = [];
    for (const key of pac) if (atl.has(key)) res.push(key.split(',').map(Number));
    return res;
};

