def ladderLength(self, beginWord: str, endWord: str, wordList: List[str]) -> int:
    if endWord not in wordList:
        return 0
    nei = defaultdict(list)
    wordList.append(beginWord)
    for word in wordList:
        for j in range(len(word)):
            pattern = word[:j] + '*' + word[j+1:]
            nei[pattern].append(word)
    visit = set([beginWord])
    queue = deque([beginWord])
    res = 1
    while queue:
        for _ in range(len(queue)):
            word = queue.popleft()
            if word == endWord:
                return res
            for j in range(len(word)):
                pattern = word[:j] + '*' + word[j+1:]
                for neiWord in nei[pattern]:
                    if neiWord not in visit:
                        visit.add(neiWord)
                        queue.append(neiWord)
        res += 1
    return 0

solution_js:
var ladderLength = function(beginWord, endWord, wordList) {
    if (!wordList.includes(endWord)) return 0;
    const nei = new Map();
    wordList.push(beginWord);
    for (const word of wordList) {
        for (let j = 0; j < word.length; j++) {
            const pat = word.slice(0,j) + '*' + word.slice(j+1);
            if (!nei.has(pat)) nei.set(pat, []);
            nei.get(pat).push(word);
        }
    }
    const visit = new Set([beginWord]);
    const queue = [beginWord];
    let qi = 0, res = 1;
    while (qi < queue.length) {
        const size = queue.length - qi;
        for (let i = 0; i < size; i++) {
            const word = queue[qi++];
            if (word === endWord) return res;
            for (let j = 0; j < word.length; j++) {
                const pat = word.slice(0,j) + '*' + word.slice(j+1);
                for (const nw of (nei.get(pat) || [])) {
                    if (!visit.has(nw)) { visit.add(nw); queue.push(nw); }
                }
            }
        }
        res++;
    }
    return 0;
};

