def maxSubArray(self, nums: List[int]) -> int:
    maxSub = nums[0]
    curSum = 0
    for n in nums:
        if curSum < 0:
            curSum = 0
        curSum += n
        maxSub = max(maxSub, curSum)
    return maxSub

solution_js:
var maxSubArray = function(nums) {
    let maxSub = nums[0], curSum = 0;
    for (const n of nums) {
        if (curSum < 0) curSum = 0;
        curSum += n;
        maxSub = Math.max(maxSub, curSum);
    }
    return maxSub;
};

