def canCompleteCircuit(self, gas: List[int], cost: List[int]) -> int:
    if sum(gas) < sum(cost):
        return -1
    tank = 0
    start = 0
    for i in range(len(gas)):
        tank += gas[i] - cost[i]
        if tank < 0:
            tank = 0
            start = i + 1
    return start

solution_js:
var canCompleteCircuit = function(gas, cost) {
    let totalGas = 0, totalCost = 0;
    for (let i = 0; i < gas.length; i++) { totalGas += gas[i]; totalCost += cost[i]; }
    if (totalGas < totalCost) return -1;
    let tank = 0, start = 0;
    for (let i = 0; i < gas.length; i++) {
        tank += gas[i] - cost[i];
        if (tank < 0) { tank = 0; start = i + 1; }
    }
    return start;
};

solution_python:
def isNStraightHand(self, hand: List[int], groupSize: int) -> bool:
    if len(hand) % groupSize:
        return False
    count = Counter(hand)
    for card in sorted(count):
        while count[card] > 0:
            for i in range(card, card + groupSize):
                if count[i] <= 0:
                    return False
                count[i] -= 1
    return True

solution_js:
var isNStraightHand = function(hand, groupSize) {
    if (hand.length % groupSize) return false;
    const count = new Map();
    for (const c of hand) count.set(c, (count.get(c) || 0) + 1);
    const sorted = [...count.keys()].sort((a, b) => a - b);
    for (const card of sorted) {
        while (count.get(card) > 0) {
            for (let i = card; i < card + groupSize; i++) {
                if ((count.get(i) || 0) <= 0) return false;
                count.set(i, count.get(i) - 1);
            }
        }
    }
    return true;
};

