def minInterval(self, intervals: List[List[int]], queries: List[int]) -> List[int]:
    intervals.sort()
    sortedQ = sorted(enumerate(queries), key=lambda x: x[1])
    res = [-1] * len(queries)
    heap = []
    j = 0
    for idx, q in sortedQ:
        while j < len(intervals) and intervals[j][0] <= q:
            l, r = intervals[j]
            heapq.heappush(heap, (r - l + 1, r))
            j += 1
        while heap and heap[0][1] < q:
            heapq.heappop(heap)
        if heap:
            res[idx] = heap[0][0]
    return res

solution_js:
var minInterval = function(intervals, queries) {
    intervals.sort((a, b) => a[0] - b[0]);
    const sortedQ = queries.map((q, i) => [q, i]).sort((a, b) => a[0] - b[0]);
    const res = new Array(queries.length).fill(-1);
    const heap = new MinPriorityQueue({ priority: x => x[0] });
    let j = 0;
    for (const [q, idx] of sortedQ) {
        while (j < intervals.length && intervals[j][0] <= q) {
            const [l, r] = intervals[j];
            heap.enqueue([r - l + 1, r]);
            j++;
        }
        while (heap.size() && heap.front().element[1] < q) heap.dequeue();
        if (heap.size()) res[idx] = heap.front().element[0];
    }
    return res;
};

