def isHappy(self, n: int) -> bool:
    seen = set()
    while n != 1:
        if n in seen:
            return False
        seen.add(n)
        n = sum(int(d) ** 2 for d in str(n))
    return True

solution_js:
var isHappy = function(n) {
    const seen = new Set();
    while (n !== 1) {
        if (seen.has(n)) return false;
        seen.add(n);
        n = String(n).split('').reduce((sum, d) => sum + d * d, 0);
    }
    return true;
};

