var DetectSquares = function() {
    this.ptsCount = new Map();
    this.pts = [];
};

DetectSquares.prototype.add = function(point) {
    const key = point[0] + ',' + point[1];
    this.ptsCount.set(key, (this.ptsCount.get(key) || 0) + 1);
    this.pts.push(point);
};

DetectSquares.prototype.count = function(point) {
    let res = 0;
    const [qx, qy] = point;
    for (const [px, py] of this.pts) {
        if (Math.abs(qx - px) !== Math.abs(qy - py) || qx === px || qy === py) continue;
        res += (this.ptsCount.get(qx + ',' + py) || 0) * (this.ptsCount.get(px + ',' + qy) || 0);
    }
    return res;
};

