def swimInWater(self, grid: List[List[int]]) -> int:
    n = len(grid)
    visited = set()
    heap = [(grid[0][0], 0, 0)]
    visited.add((0, 0))
    while heap:
        t, r, c = heapq.heappop(heap)
        if r == n - 1 and c == n - 1:
            return t
        for dr, dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < n and 0 <= nc < n and (nr, nc) not in visited:
                visited.add((nr, nc))
                heapq.heappush(heap, (max(t, grid[nr][nc]), nr, nc))
    return -1

solution_js:
var swimInWater = function(grid) {
    const n = grid.length;
    const visited = new Set();
    const heap = new MinPriorityQueue({ priority: x => x[0] });
    heap.enqueue([grid[0][0], 0, 0]);
    visited.add('0,0');
    while (heap.size()) {
        const [t, r, c] = heap.dequeue().element;
        if (r === n-1 && c === n-1) return t;
        for (const [dr,dc] of [[1,0],[-1,0],[0,1],[0,-1]]) {
            const nr = r+dr, nc = c+dc;
            const key = nr+','+nc;
            if (nr >= 0 && nc >= 0 && nr < n && nc < n && !visited.has(key)) {
                visited.add(key);
                heap.enqueue([Math.max(t, grid[nr][nc]), nr, nc]);
            }
        }
    }
    return -1;
};

